// Secure version of app.js with security best practices implemented
const express = require('express');
const https = require('https');
const http = require('http');
const fs = require('fs');
const helmet = require('helmet');
const cors = require('cors');
const rateLimit = require('express-rate-limit');
const { query, validationResult } = require('express-validator');
const jwt = require('jsonwebtoken');
const morgan = require('morgan');
const winston = require('winston');
require('dotenv').config();

// ============== LOGGING SETUP ==============
const logger = winston.createLogger({
  level: process.env.LOG_LEVEL || 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'error.log', level: 'error' }),
    new winston.transports.File({ filename: 'combined.log' }),
  ],
});

if (process.env.NODE_ENV !== 'production') {
  logger.add(new winston.transports.Console({
    format: winston.format.simple(),
  }));
}

// ============== MIDDLEWARE SETUP ==============
const app = express();

// Security headers
app.use(helmet());

// CORS configuration
const corsOptions = {
  origin: (process.env.ALLOWED_ORIGINS || 'https://yourdomain.com').split(','),
  credentials: true,
  optionsSuccessStatus: 200,
  methods: ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS'],
  allowedHeaders: ['Content-Type', 'Authorization'],
  maxAge: 3600,
};
app.use(cors(corsOptions));

// Request logging
app.use(morgan('combined', {
  skip: (req, res) => res.statusCode < 400,
}));

// Body parsing with size limits
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ limit: '10kb', extended: false }));

// ============== RATE LIMITING ==============
const generalLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP address',
  standardHeaders: true,
  legacyHeaders: false,
  skip: (req) => process.env.NODE_ENV === 'development',
});

const authLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 5, // 5 attempts per 15 minutes
  skipSuccessfulRequests: true,
  message: 'Too many authentication attempts',
});

app.use(generalLimiter);

// ============== AUTHENTICATION MIDDLEWARE ==============
const authenticateUser = (req, res, next) => {
  try {
    const authHeader = req.headers.authorization;

    if (!authHeader || !authHeader.startsWith('Bearer ')) {
      logger.warn({
        event: 'unauthorized_access_attempt',
        endpoint: req.path,
        ip: req.ip,
      });
      return res.status(401).json({ error: 'Missing or invalid authorization header' });
    }

    const token = authHeader.substring(7); // Remove 'Bearer ' prefix

    if (!process.env.JWT_SECRET) {
      logger.error('JWT_SECRET not configured');
      return res.status(500).json({ error: 'Internal server error' });
    }

    const decoded = jwt.verify(token, process.env.JWT_SECRET);
    req.user = decoded;
    next();
  } catch (err) {
    logger.warn({
      event: 'invalid_token',
      error: err.message,
      ip: req.ip,
    });
    return res.status(403).json({ error: 'Invalid or expired token' });
  }
};

// ============== ROUTES ==============

// Health check endpoint (public, but should still be rate limited)
app.get('/health', (req, res) => {
  res.status(200).json({
    status: 'ok',
    timestamp: new Date().toISOString(),
    uptime: process.uptime(),
  });
});

// Get users endpoint (protected, with input validation)
app.get('/users',
  authenticateUser,
  query('limit')
    .optional()
    .isInt({ min: 1, max: 100 })
    .withMessage('Limit must be between 1 and 100'),
  query('offset')
    .optional()
    .isInt({ min: 0 })
    .withMessage('Offset must be a non-negative integer'),
  (req, res) => {
    // Validate input
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      logger.warn({
        event: 'validation_error',
        errors: errors.array(),
        userId: req.user.id,
      });
      return res.status(400).json({ errors: errors.array() });
    }

    // Only return data that the user is authorized to access
    // In a real app, this would query a database with proper authorization checks
    const limit = Math.min(parseInt(req.query.limit) || 10, 100);
    const offset = parseInt(req.query.offset) || 0;

    // Example: Restrict data based on user role
    let users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Only admins can see all users
    if (req.user.role !== 'admin') {
      users = users.filter(u => u.id === req.user.id);
    }

    const paginatedUsers = users.slice(offset, offset + limit);

    logger.info({
      event: 'users_accessed',
      userId: req.user.id,
      count: paginatedUsers.length,
    });

    res.status(200).json({
      data: paginatedUsers,
      total: users.length,
      limit,
      offset,
    });
  }
);

// Login endpoint (with rate limiting)
app.post('/login', authLimiter, express.json(), (req, res) => {
  try {
    const { username, password } = req.body;

    // Validate input
    if (!username || !password) {
      logger.warn({
        event: 'login_invalid_credentials',
        ip: req.ip,
      });
      return res.status(400).json({ error: 'Username and password required' });
    }

    // In production, verify credentials against a database with hashed passwords
    // using bcrypt: const valid = await bcrypt.compare(password, hashedPassword);
    if (username === 'admin' && password === process.env.ADMIN_PASSWORD) {
      const token = jwt.sign(
        { id: 1, username: 'admin', role: 'admin' },
        process.env.JWT_SECRET,
        { expiresIn: '1h' }
      );

      logger.info({
        event: 'login_success',
        username,
        ip: req.ip,
      });

      return res.status(200).json({ token });
    }

    logger.warn({
      event: 'login_failed',
      username,
      ip: req.ip,
    });
    res.status(401).json({ error: 'Invalid credentials' });
  } catch (err) {
    logger.error({
      event: 'login_error',
      error: err.message,
      ip: req.ip,
    });
    res.status(500).json({ error: 'Internal server error' });
  }
});

// ============== ERROR HANDLING ==============

// 404 handler
app.use((req, res) => {
  logger.warn({
    event: 'not_found',
    path: req.path,
    method: req.method,
    ip: req.ip,
  });
  res.status(404).json({ error: 'Not found' });
});

// Global error handler (must be last)
app.use((err, req, res, next) => {
  logger.error({
    event: 'unhandled_error',
    error: err.message,
    stack: err.stack,
    path: req.path,
    method: req.method,
    ip: req.ip,
  });

  const status = err.status || 500;
  const message = process.env.NODE_ENV === 'production'
    ? 'Internal server error'
    : err.message;

  res.status(status).json({
    error: message,
    ...(process.env.NODE_ENV !== 'production' && { requestId: req.id }),
  });
});

// Handle unhandled promise rejections
process.on('unhandledRejection', (reason, promise) => {
  logger.error({
    event: 'unhandled_rejection',
    reason: String(reason),
    promise: String(promise),
  });
});

// ============== SERVER STARTUP ==============

if (process.env.NODE_ENV === 'production' && process.env.SSL_KEY_PATH && process.env.SSL_CERT_PATH) {
  // HTTPS for production
  const options = {
    key: fs.readFileSync(process.env.SSL_KEY_PATH),
    cert: fs.readFileSync(process.env.SSL_CERT_PATH),
  };

  https.createServer(options, app).listen(3000, () => {
    logger.info('Secure server running on port 3000 (HTTPS)');
  });

  // Redirect HTTP to HTTPS
  const httpApp = express();
  httpApp.all('*', (req, res) => {
    res.redirect(`https://${req.hostname}${req.url}`);
  });
  http.createServer(httpApp).listen(80);
} else {
  // HTTP for development
  app.listen(3000, () => {
    logger.info('Server running on port 3000 (HTTP - Development only)');
  });
}

module.exports = app;

