  res.setHeader('Strict-Transport-Security', 'max-age=31536000; includeSubDomains');
  res.setHeader('X-XSS-Protection', '1; mode=block');
  next();
});
```

---

#### **5. No Rate Limiting** ⚠️ **HIGH**

**Issue:** The `/users` endpoint has no rate limiting.

**Risk:**
- **Denial of Service (DoS)** - Attackers can exhaust server resources
- **Brute Force Attacks** - If authentication is added, no protection against brute forcing

**Recommendation:**
```javascript
const rateLimit = require('express-rate-limit');

const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again later.',
  standardHeaders: true, // Return rate limit info in the `RateLimit-*` headers
  legacyHeaders: false, // Disable the `X-RateLimit-*` headers
});

app.use('/users', limiter);
```

---

#### **6. No CORS Configuration** ⚠️ **MEDIUM**

**Issue:** No explicit CORS configuration.

**Risk:**
- **Cross-Origin Requests** - May be overly permissive or too restrictive
- **Data exposure** to unauthorized domains

**Recommendation:**
```javascript
const cors = require('cors');

const corsOptions = {
  origin: process.env.ALLOWED_ORIGINS?.split(',') || ['https://example.com'],
  credentials: true,
  methods: ['GET', 'POST'],
  allowedHeaders: ['Content-Type', 'Authorization'],
  maxAge: 86400, // 24 hours
};

app.use(cors(corsOptions));
```

---

#### **7. No HTTPS Enforcement** ⚠️ **HIGH**

**Issue:** Application listens on HTTP without HTTPS.

**Risk:**
- **Man-in-the-Middle Attacks** - Credentials and data can be intercepted

**Recommendation:**
```javascript
const https = require('https');
const fs = require('fs');

const options = {
  key: fs.readFileSync(process.env.SSL_KEY_PATH),
  cert: fs.readFileSync(process.env.SSL_CERT_PATH),
};

https.createServer(options, app).listen(3000, () => {
  console.log('Secure server running on port 3000');
});

// In production, use a reverse proxy (nginx, AWS ALB) to handle SSL
```

---

#### **8. No Logging & Monitoring** ⚠️ **MEDIUM**

**Issue:** No security event logging or error handling.

**Risk:**
- **Undetected Security Breaches** - Cannot audit or investigate incidents
- **Information Disclosure** - Errors expose stack traces

**Recommendation:**
```javascript
const winston = require('winston');

const logger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'error.log', level: 'error' }),
    new winston.transports.File({ filename: 'security.log' }),
  ],
});

// Log authentication attempts
app.get('/users', authenticate, (req, res) => {
  logger.info('Users endpoint accessed', {
    userId: req.user.id,
    timestamp: new Date().toISOString(),
    ip: req.ip,
  });

  res.json([...]);
});

// Global error handler
app.use((err, req, res, next) => {
  logger.error('Unhandled error', {
    message: err.message,
    stack: process.env.NODE_ENV === 'development' ? err.stack : undefined,
  });

  res.status(500).json({ error: 'Internal Server Error' });
});
```

---

#### **9. No Data Validation on GET Parameters** ⚠️ **HIGH**

**Issue:** While current code doesn't use parameters, Express apps often add filtering without validation.

**Recommendation:**
```javascript
// VULNERABLE - Don't do this:
app.get('/users/:id', (req, res) => {
  // Direct string concatenation can lead to NoSQL injection
  // db.query("SELECT * FROM users WHERE id = " + req.params.id);
});

// SECURE - Do this instead:
app.get('/users/:id', [
  param('id').isInt().toInt(),
], (req, res) => {
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    return res.status(400).json({ errors: errors.array() });
  }

  const { id } = req.params;
  // Now id is guaranteed to be an integer
});
```

---

### **OWASP Top 10 (2021) Coverage**

| Vulnerability | Status | Severity |
|---|---|---|
| A01:2021 – Broken Access Control | ❌ VULNERABLE | Critical |
| A02:2021 – Cryptographic Failures | ⚠️ AT RISK | High |
| A03:2021 – Injection | ⚠️ AT RISK | High |
| A04:2021 – Insecure Design | ❌ VULNERABLE | High |
| A05:2021 – Security Misconfiguration | ❌ VULNERABLE | High |
| A06:2021 – Vulnerable Components | ⚠️ AT RISK | Medium |
| A07:2021 – Authentication Failures | ❌ VULNERABLE | Critical |
| A08:2021 – Data Integrity Failures | ⚠️ AT RISK | High |
| A09:2021 – Logging & Monitoring | ❌ MISSING | High |
| A10:2021 – SSRF | ⚠️ AT RISK | Medium |

---

### **Secure Application Template**

```javascript
const express = require('express');
const helmet = require('helmet');
const cors = require('cors');
const rateLimit = require('express-rate-limit');
const jwt = require('jsonwebtoken');
const { query, validationResult } = require('express-validator');
require('dotenv').config();

const app = express();

// Security middleware
app.use(helmet());
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS?.split(',') || ['http://localhost:3001'],
  credentials: true,
}));

app.use(rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
}));

app.use(express.json({ limit: '10kb' })); // Prevent large payloads

// Authentication middleware
const authenticate = (req, res, next) => {
  const token = req.headers.authorization?.split(' ')[1];
  if (!token) return res.status(401).json({ error: 'Unauthorized' });

  try {
    req.user = jwt.verify(token, process.env.JWT_SECRET);
    next();
  } catch {
    return res.status(403).json({ error: 'Forbidden' });
  }
};

// Health check (public, safe)
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// Protected endpoint
app.get('/users', authenticate, (req, res) => {
  if (req.user.role !== 'admin') {
    return res.status(403).json({ error: 'Insufficient permissions' });
  }

  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ]);
});

// Error handling
app.use((err, req, res, next) => {
  console.error(err);
  res.status(500).json({ error: 'Internal Server Error' });
});

app.listen(3000, () => {
  console.log('Secure server running on port 3000');
});

module.exports = app;
```

---

### **Action Items (Priority Order)**

1. **Immediate:** Remove `.env.test` from version control and add to `.gitignore`
2. **Immediate:** Add authentication to `/users` endpoint
3. **High:** Implement helmet.js for security headers
4. **High:** Add rate limiting
5. **High:** Implement input validation with express-validator
6. **High:** Deploy on HTTPS
7. **Medium:** Add logging and monitoring
8. **Medium:** Configure explicit CORS policy

---

This application requires significant security hardening before production deployment. Would you like me to help implement any of these recommendations?

